const languageCatalogCodes = [
  ...iso6391LanguageCodes,
  ...verifiedLanguageCodes.filter((code) => !iso6391LanguageCodes.includes(code as (typeof iso6391LanguageCodes)[number])),
];

export const languages: LanguageOption[] = languageCatalogCodes
  .map((code) => {
    const verified = isLanguageCode(code);
    const meta = verified ? verifiedLanguageMeta[code] : undefined;

    return {
      code,
      flag: meta?.flag ?? "🌐",
      name: meta?.name ?? displayName(code, "en"),
      nativeName: meta?.nativeName ?? languageNameFallbacks[code] ?? displayName(code, code),
      dir: rtlLanguageCodes.has(code) ? ("rtl" as const) : undefined,
      available: verified,
    };
  })
  .sort((left, right) => {
    const leftPriority = verifiedLanguageCodes.indexOf(left.code as LanguageCode);
    const rightPriority = verifiedLanguageCodes.indexOf(right.code as LanguageCode);
    if (leftPriority !== -1 || rightPriority !== -1) {
      if (leftPriority === -1) return 1;
      if (rightPriority === -1) return -1;
      return leftPriority - rightPriority;
    }
    if (left.available !== right.available) return left.available ? -1 : 1;
    return left.name.localeCompare(right.name, "en");
  });

