function sequenceSpecificActivities<const FamilyCode extends string>(
  familyCodes: readonly FamilyCode[],
  entries: Partial<Record<Exclude<LanguageCode, "en" | "en-US">, readonly (readonly [string, string, string])[]>>,
): Partial<Record<Exclude<LanguageCode, "en" | "en-US">, Record<FamilyCode, { title: string; prompt: string; prep: string }>>> {
  return Object.fromEntries(
    Object.entries(entries).map(([language, values]) => [
      language,
      Object.fromEntries(values.map(([title, prompt, prep], index) => [familyCodes[index], { title, prompt, prep }])),
    ]),
  ) as Partial<Record<Exclude<LanguageCode, "en" | "en-US">, Record<FamilyCode, { title: string; prompt: string; prep: string }>>>;
}

