const generatedScriptedSpecificActivities: Partial<Record<Exclude<LanguageCode, "en" | "en-US">, SpecificActivityMap>> =
  Object.fromEntries(
    Object.entries(scriptedFallbackCopy).map(([language, copy]) => [
      language,
      Object.fromEntries(
        scriptedFallbackFamilyCodes.map((family, index) => [
          family,
          {
            title: `${copy.titlePrefix} ${index + 1}`,
            prompt: copy.prompt,
            prep: copy.prep,
          },
        ]),
      ),
    ]),
  ) as Partial<Record<Exclude<LanguageCode, "en" | "en-US">, SpecificActivityMap>>;

function combineSpecificActivities(
  language: Exclude<LanguageCode, "en" | "en-US">,
  base: SpecificActivityMap = {},
): SpecificActivityMap {
  return {
    ...base,
    ...(generatedScriptedSpecificActivities[language] ?? {}),
    ...(scriptedSpecificActivities[language] ?? {}),
    ...(additionalScriptedSpecificActivities[language] ?? {}),
    ...(expandedScriptedSpecificActivities[language] ?? {}),
    ...(precisionScriptedSpecificActivities[language] ?? {}),
    ...(continuedScriptedSpecificActivities[language] ?? {}),
  };
}

