function compactIdeaTemplates(entries: Record<string, { title: string; prompt: string; prep: string }>): Record<string, GermanTemplateSet> {
  return Object.fromEntries(
    Object.entries(entries).map(([category, entry]) => [
      category,
      {
        titles: [entry.title],
        prompts: [entry.prompt],
        prep: [entry.prep],
      },
    ]),
  );
}

