export function labelFor(
  kind: "category" | "budget" | "duration",
  value: string,
  language: LanguageCode,
  market = budgetMarketFor(language),
) {
  if (kind === "budget") return formatBudgetLabel(value, language, market);

  const source = kind === "category" ? categoryLabels : durationLabels;
  return source[language]?.[value] ?? value;
}

export function hasSpecificIdeaLocalization(family: string, language: LanguageCode): boolean {
  if (language === "en" || language === "en-US") return true;
  return Boolean(localizedIdeaPacks[language]?.specificActivities[family]);
}

export function localizeIdea(idea: DateIdea, language: LanguageCode, market = budgetMarketFor(language)): DateIdea {
  if (language === "en" || language === "en-US") return idea;

  const pack = localizedIdeaPacks[language];
  const index = Number.parseInt(idea.id.replace(/\D/g, ""), 10) || 1;
  const templates = pack.templates[idea.category] ?? pack.templates.Home;
  const tags = idea.tags.map((tag) => pack.tags[tag] ?? tag.toLowerCase()).slice(0, 4);
  const focus = [...new Set(tags)].slice(0, 3);
  const specific = pack.specificActivities[idea.family];
  const sentenceSeparator = pack.sentenceSeparator ?? ". ";
  const sentenceEnd = sentenceSeparator.trimEnd();
  const promptDetails = [
    `${pack.durationLabel}${pack.labelSeparator}${labelFor("duration", idea.duration, language)}`,
    `${pack.budgetLabel}${pack.labelSeparator}${labelFor("budget", idea.budget, language, market)}`,
    ...focus,
  ];

  if (specific) {
    const titleFocus = focus.length > 0 ? `: ${focus.slice(0, 3).join(" + ")}` : "";
    const promptBase = specific.prompt.replace(/[.!?。؟।]+$/u, "");

    return {
      ...idea,
      title: `${specific.title}${titleFocus}`,
      prompt: `${promptBase}${sentenceSeparator}${promptDetails.join(" · ")}${sentenceEnd}`,
      prep: `${specific.prep}${sentenceSeparator}${pack.durationLabel}${pack.labelSeparator}${labelFor("duration", idea.duration, language)}${sentenceSeparator}${pack.budgetLabel}${pack.labelSeparator}${labelFor("budget", idea.budget, language, market)}${sentenceEnd}`,
      tags,
    };
  }

  const mood = tags[0] ?? pack.fallbackMood;
  const titleFocus = focus.length > 0 ? focus.slice(0, 3).join(" + ") : mood;
  const titleTemplate = templates.titles[index % templates.titles.length];
  const focusedTitle = titleTemplate.includes("{mood}") ? titleTemplate.replace("{mood}", titleFocus) : `${titleTemplate}: ${titleFocus}`;
  const title = `${focusedTitle} · ${labelFor("category", idea.category, language)}`;
  const promptBase = templates.prompts[(index + 1) % templates.prompts.length].replace(/[.!?。؟।]+$/u, "");
  const prompt = `${promptBase}${sentenceSeparator}${promptDetails.join(" · ")}${sentenceEnd}`;
  const prep = `${templates.prep[(index + 2) % templates.prep.length]}${sentenceSeparator}${pack.durationLabel}${pack.labelSeparator}${labelFor("duration", idea.duration, language)}${sentenceSeparator}${pack.budgetLabel}${pack.labelSeparator}${labelFor("budget", idea.budget, language, market)}${sentenceEnd}`;

  return {
    ...idea,
    title,
    prompt,
    prep,
    tags,
  };
}
